import React, { useState } from 'react';

const OVERSCAN = 4;

export default function VirtualList({ items, rowHeight = 36, height = 300 }) {
  const [scrollTop, setScrollTop] = useState(0);

  const count = items.length;
  const start = Math.max(0, Math.floor(scrollTop / rowHeight) - OVERSCAN);
  const visible = Math.ceil(height / rowHeight) + OVERSCAN * 2;
  const end = Math.min(count, start + visible);
  const slice = items.slice(start, end);

  return (
    <div
      onScroll={(e) => setScrollTop(e.currentTarget.scrollTop)}
      style={{ height, overflowY: 'auto', border: '1px solid #cbd5e1', borderRadius: 8, maxWidth: 320 }}
    >
      <div style={{ height: count * rowHeight, position: 'relative' }}>
        <div style={{ transform: `translateY(${start * rowHeight}px)` }}>
          {slice.map((item) => (
            <div
              key={item.id}
              style={{ height: rowHeight, lineHeight: `${rowHeight}px`, padding: '0 14px', borderBottom: '1px solid #f1f5f9', boxSizing: 'border-box', background: item.id % 2 ? '#fafafa' : '#fff' }}
            >
              {item.label}
            </div>
          ))}
        </div>
      </div>
    </div>
  );
}

