import { Component, Input } from '@angular/core';
import { NgModule } from '@angular/core';
import { BrowserModule } from '@angular/platform-browser';

interface Item { id: number; label: string; }

@Component({
  selector: 'app-virtual-list',
  template: `
    <div
      (scroll)="onScroll($event)"
      [style.height.px]="height"
      style="overflow-y: auto; border: 1px solid #cbd5e1; border-radius: 8px; max-width: 320px;"
    >
      <div [style.height.px]="items.length * rowHeight" style="position: relative;">
        <div [style.transform]="'translateY(' + (start * rowHeight) + 'px)'">
          <div
            *ngFor="let item of slice; trackBy: trackById"
            [style.height.px]="rowHeight"
            [style.line-height.px]="rowHeight"
            [style.background]="item.id % 2 ? '#fafafa' : '#fff'"
            style="padding: 0 14px; border-bottom: 1px solid #f1f5f9; box-sizing: border-box;"
          >{{ item.label }}</div>
        </div>
      </div>
    </div>
  `,
})
export class VirtualListComponent {
  @Input() items: Item[] = [];
  @Input() rowHeight = 36;
  @Input() height = 300;
  readonly OVERSCAN = 4;
  scrollTop = 0;

  onScroll(e: Event): void {
    this.scrollTop = (e.target as HTMLElement).scrollTop;
  }

  get start(): number {
    return Math.max(0, Math.floor(this.scrollTop / this.rowHeight) - this.OVERSCAN);
  }

  get end(): number {
    return Math.min(
      this.items.length,
      this.start + Math.ceil(this.height / this.rowHeight) + this.OVERSCAN * 2
    );
  }

  get slice(): Item[] {
    return this.items.slice(this.start, this.end);
  }

  trackById(_i: number, item: Item): number {
    return item.id;
  }
}

@Component({
  selector: 'app-root',
  template: `
    <div style="font-family: sans-serif; padding: 20px;">
      <h1>Virtualized List Demo</h1>
      <p style="color: #666;">10,000 rows — only the visible ones are in the DOM.</p>
      <app-virtual-list [items]="items" [rowHeight]="36" [height]="300"></app-virtual-list>
    </div>
  `,
})
export class AppComponent {
  items: Item[] = Array.from({ length: 10000 }, (_, i) => ({ id: i, label: 'Row #' + (i + 1) }));
}

@NgModule({
  declarations: [AppComponent, VirtualListComponent],
  imports: [BrowserModule],
  bootstrap: [AppComponent],
})
export class AppModule {}
